-
-    _checkConptyOutput = false;
-    _logConpty = true;
-
-    // Print two lines of text:
-    // |AAAAAAAAAAAAA BBBBBB| <wrap>
-    // |BBBBBBBB_           | <break>
-    // (cursor on the '_')
-
-    sm.ProcessString(L"\x1b[?25l");
-    sm.ProcessString(std::wstring(50, L'A'));
